import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ExamConfig, ExamData, CognitiveLevel } from "../types";

// Define the response schema strictly to ensure valid JSON output
const examSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "Tên đề thi, ví dụ: Đề kiểm tra 1 tiết Lịch sử 12 - [Chủ đề]" },
    multipleChoice: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Mảng gồm 4 nội dung lựa chọn. CHỈ GHI NỘI DUNG CÂU TRẢ LỜI. TUYỆT ĐỐI KHÔNG GHI KÝ TỰ 'A.', 'B.', 'C.', 'D.' Ở ĐẦU."
          },
          correctAnswer: { type: Type.STRING, description: "Chỉ ghi A, B, C hoặc D" },
          level: { type: Type.STRING, description: "Mức độ nhận thức (Nhận biết, Thông hiểu, Vận dụng, Vận dụng cao)" }
        },
        required: ["question", "options", "correctAnswer", "level"]
      }
    },
    essay: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          rubric: { type: Type.STRING, description: "Hướng dẫn chấm/đáp án ngắn gọn" },
          level: { type: Type.STRING }
        },
        required: ["question", "rubric", "level"]
      }
    }
  },
  required: ["title", "multipleChoice", "essay"]
};

export const generateExam = async (config: ExamConfig): Promise<ExamData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const distributionText = Object.entries(config.distribution)
    .map(([level, percent]) => `- ${level}: ${percent}%`)
    .join('\n');

  const prompt = `
    Đóng vai một giáo viên Lịch sử chuyên nghiệp tại Trường THCS Phương Lâm, có kinh nghiệm ra đề thi chuẩn theo quy định.
    Hãy soạn một đề thi môn Lịch sử với các yêu cầu sau:

    1. **Chủ đề:** ${config.topic}
    2. **Đối tượng:** Học sinh ${config.grade}
    3. **Cấu trúc đề thi:**
       - Phần 1: ${config.mcCount} câu trắc nghiệm khách quan (4 lựa chọn).
       - Phần 2: ${config.essayCount} câu tự luận.
    4. **Ma trận nhận thức (Phân bố mức độ khó):**
       ${distributionText}

    **Yêu cầu quan trọng về định dạng (Format):**
    - **TUYỆT ĐỐI KHÔNG** thêm các ký tự đánh số thứ tự như "A.", "B.", "C.", "D." hoặc "1.", "2." vào đầu nội dung của các phương án trắc nghiệm trong JSON. Hệ thống hiển thị sẽ tự động thêm vào.
    - Ví dụ SAI: "A. Chiến thắng Bạch Đằng"
    - Ví dụ ĐÚNG: "Chiến thắng Bạch Đằng"

    **Yêu cầu về nội dung:**
    - Văn phong chuẩn mực, sư phạm, nghiêm túc.
    - Câu hỏi trắc nghiệm phải có tính nhiễu tốt, không quá dễ đoán.
    - Câu hỏi tự luận phải kích thích tư duy, phù hợp với mức độ Vận dụng và Vận dụng cao.
    - Đảm bảo chính xác về kiến thức lịch sử.
    - Nội dung câu hỏi phải tuân thủ đúng tỷ lệ phần trăm mức độ nhận thức đã yêu cầu.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Using 3.0 Pro Preview as requested for complex reasoning
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: examSchema,
        thinkingConfig: { thinkingBudget: 2048 } // Use reasoning to balance the exam matrix
      }
    });

    const text = response.text;
    if (!text) throw new Error("Không nhận được dữ liệu từ Gemini.");

    const rawData = JSON.parse(text);

    // Map raw data to our typed structure with IDs
    const examData: ExamData = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      config: config,
      title: rawData.title,
      multipleChoice: rawData.multipleChoice.map((q: any) => ({ ...q, id: crypto.randomUUID() })),
      essay: rawData.essay.map((q: any) => ({ ...q, id: crypto.randomUUID() }))
    };

    return examData;

  } catch (error) {
    console.error("Lỗi khi tạo đề:", error);
    throw error;
  }
};

import React from 'react';
import { ExamData, MultipleChoiceQuestion, EssayQuestion } from '../types';
import { FileDown, CheckCircle2, PlayCircle } from 'lucide-react';

interface Props {
  exam: ExamData;
  onTakeExam: () => void;
}

export const ExamPaper: React.FC<Props> = ({ exam, onTakeExam }) => {

  const exportToWord = () => {
    // Basic HTML to Doc export strategy
    const header = "<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>Export HTML to Word Document with JavaScript</title><style>body{font-family: 'Times New Roman', serif; font-size: 13pt;}</style></head><body>";

    // Get the HTML content from the preview div
    const examContent = document.getElementById('exam-preview-content')?.innerHTML;

    if (!examContent) return;

    const footer = "</body></html>";
    const sourceHTML = header + examContent + footer;

    const source = 'data:application/vnd.ms-word;charset=utf-8,' + encodeURIComponent(sourceHTML);

    const fileDownload = document.createElement("a");
    document.body.appendChild(fileDownload);
    fileDownload.href = source;
    fileDownload.download = `${exam.title.replace(/\s+/g, '_')}.doc`;
    fileDownload.click();
    document.body.removeChild(fileDownload);
  };

  // Helper function to clean option text (remove "A.", "A)", "a." from start)
  const cleanOptionText = (text: string) => {
    // Regex matches "A.", "A)", "A " repeatedly at the start to handle cases like "A. A. Content"
    return text.replace(/^([A-D][.:)]\s*)+/i, "").trim();
  };

  return (
    <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full">
      {/* Toolbar */}
      <div className="p-4 border-b border-gray-200 flex flex-col sm:flex-row justify-between items-center gap-3 bg-gray-50 rounded-t-xl">
        <h3 className="font-bold text-gray-700 hidden sm:block">Xem trước Đề thi</h3>
        <div className="flex w-full sm:w-auto gap-2">
            <button
            onClick={onTakeExam}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition shadow-sm text-sm font-medium"
            >
            <PlayCircle className="w-4 h-4" />
            Làm bài Online
            </button>
            <button
            onClick={exportToWord}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition shadow-sm text-sm font-medium"
            >
            <FileDown className="w-4 h-4" />
            Xuất file Word
            </button>
        </div>
      </div>

      {/* Paper Content */}
      <div className="flex-1 overflow-auto p-4 sm:p-8 bg-gray-50">
        <div 
          id="exam-preview-content" 
          className="max-w-[210mm] mx-auto bg-white p-6 sm:p-[20mm] shadow-md min-h-[297mm]"
          style={{ fontFamily: "'Times New Roman', Times, serif" }}
        >
          {/* Header */}
          <div className="text-center mb-6">
            <h1 className="text-lg font-bold uppercase mb-1">Trường THCS Phương Lâm</h1>
            <h2 className="text-xl font-bold uppercase mb-4">{exam.title}</h2>
            <div className="flex justify-between text-sm italic mb-4 px-8">
              <p>Môn: Lịch Sử - {exam.config.grade}</p>
              <p>Thời gian làm bài: 45 phút</p>
            </div>
            <div className="border-t-2 border-black w-1/3 mx-auto mb-6"></div>
          </div>

          {/* Part 1: Multiple Choice */}
          {exam.multipleChoice.length > 0 && (
            <div className="mb-6">
              <h3 className="font-bold text-lg mb-3 uppercase">I. Phần Trắc nghiệm ({exam.multipleChoice.length} câu)</h3>
              <div className="space-y-4">
                {exam.multipleChoice.map((q, index) => (
                  <div key={q.id} className="break-inside-avoid">
                    <p className="font-semibold mb-1">
                      <span className="underline">Câu {index + 1}:</span> {q.question} 
                      <span className="text-xs font-normal text-gray-500 ml-2 italic">[{q.level}]</span>
                    </p>
                    <div className="grid grid-cols-2 gap-x-4 gap-y-1 ml-4">
                      {q.options.map((opt, i) => {
                        const label = String.fromCharCode(65 + i); // A, B, C, D
                        return (
                          <div key={i} className={label === q.correctAnswer ? "font-bold text-blue-800" : ""}>
                            {label}. {cleanOptionText(opt)}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Part 2: Essay */}
          {exam.essay.length > 0 && (
            <div>
              <h3 className="font-bold text-lg mb-3 uppercase mt-6">II. Phần Tự luận ({exam.essay.length} câu)</h3>
              <div className="space-y-6">
                {exam.essay.map((q, index) => (
                  <div key={q.id} className="break-inside-avoid">
                    <p className="font-semibold mb-2">
                      <span className="underline">Câu {index + 1}:</span> {q.question}
                      <span className="text-xs font-normal text-gray-500 ml-2 italic">[{q.level}]</span>
                    </p>
                    <div className="ml-4 p-3 bg-gray-50 border-l-4 border-gray-300 text-sm">
                      <span className="font-bold italic underline">Hướng dẫn chấm:</span> {q.rubric}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ExamData } from '../types';
import { Clock, CheckCircle, XCircle, ChevronLeft, Send, Award, RotateCcw } from 'lucide-react';

interface Props {
  exam: ExamData;
  onExit: () => void;
}

export const StudentExam: React.FC<Props> = ({ exam, onExit }) => {
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(45 * 60); // 45 minutes in seconds

  useEffect(() => {
    if (isSubmitted) return;
    const timer = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 0) {
          handleSubmit();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [isSubmitted]);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const handleOptionSelect = (questionId: string, optionKey: string) => {
    if (isSubmitted) return;
    setAnswers(prev => ({ ...prev, [questionId]: optionKey }));
  };

  const cleanOptionText = (text: string) => {
    return text.replace(/^([A-D][.:)]\s*)+/i, "").trim();
  };

  const handleSubmit = () => {
    if (isSubmitted) return;

    // Calculate Score (Only Multiple Choice)
    let correctCount = 0;
    exam.multipleChoice.forEach(q => {
      if (answers[q.id] === q.correctAnswer) {
        correctCount++;
      }
    });

    // Score calculation logic:
    // Assume scale 10. 
    // If there is essay, split score (e.g., 70% MC, 30% Essay).
    // For auto-grading demo, we calculate MC score on a scale of 10 relative to MC count if no essay, 
    // or display raw correct count.

    // Let's display Correct/Total for clarity.
    setScore(correctCount);
    setIsSubmitted(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const getScoreColor = () => {
    const percentage = score / exam.multipleChoice.length;
    if (percentage >= 0.8) return 'text-green-600';
    if (percentage >= 0.5) return 'text-yellow-600';
    return 'text-red-600';
  };

  return (
    <div className="bg-gray-50 min-h-screen pb-12 font-sans">
      {/* Header */}
      <div className="bg-white shadow-sm sticky top-0 z-40 border-b border-gray-200">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <button 
            onClick={onExit}
            className="flex items-center gap-1 text-gray-600 hover:text-gray-900 transition"
          >
            <ChevronLeft className="w-5 h-5" />
            <span className="hidden sm:inline">Quay lại</span>
          </button>

          <div className="flex flex-col items-center">
             <h1 className="font-bold text-gray-800 text-sm sm:text-base truncate max-w-[200px] sm:max-w-md">
              {exam.title}
             </h1>
             {!isSubmitted && (
               <div className={`text-xs font-mono font-bold flex items-center gap-1 ${timeLeft < 300 ? 'text-red-500 animate-pulse' : 'text-blue-600'}`}>
                 <Clock className="w-3 h-3" />
                 {formatTime(timeLeft)}
               </div>
             )}
          </div>

          <div className="w-20 flex justify-end">
            {isSubmitted && (
                <span className={`font-bold text-lg ${getScoreColor()}`}>
                  {score}/{exam.multipleChoice.length}
                </span>
            )}
          </div>
        </div>
      </div>

      <div className="max-w-3xl mx-auto p-4 sm:p-6 space-y-8">

        {/* Result Banner */}
        {isSubmitted && (
          <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-edu-500 animate-fade-in">
            <div className="flex items-center gap-4 mb-4">
              <div className="bg-edu-100 p-3 rounded-full text-edu-600">
                <Award className="w-8 h-8" />
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-800">Kết quả bài làm</h2>
                <p className="text-gray-600">
                  Bạn đã trả lời đúng <strong className={getScoreColor()}>{score}/{exam.multipleChoice.length}</strong> câu trắc nghiệm.
                </p>
              </div>
            </div>
            <p className="text-sm text-gray-500 italic">
              * Đối với phần tự luận, vui lòng đối chiếu bài làm của bạn với đáp án gợi ý bên dưới.
            </p>
            <button 
               onClick={onExit}
               className="mt-4 px-4 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg font-medium transition flex items-center gap-2"
            >
              <RotateCcw className="w-4 h-4" /> Làm đề khác
            </button>
          </div>
        )}

        {/* School Header on Paper */}
        <div className="bg-white rounded-xl shadow-sm p-6 text-center border border-gray-100">
            <h3 className="text-sm font-bold text-gray-500 uppercase">Trường THCS Phương Lâm</h3>
            <h2 className="text-xl sm:text-2xl font-bold text-edu-900 mt-1">{exam.title}</h2>
            <div className="mt-2 text-sm text-gray-500">
              Môn: Lịch Sử • {exam.config.grade}
            </div>
        </div>

        {/* Multiple Choice Section */}
        {exam.multipleChoice.length > 0 && (
          <div className="space-y-6">
            <div className="flex items-center gap-2 mb-4 border-b pb-2">
              <span className="bg-edu-600 text-white text-xs font-bold px-2 py-1 rounded">PHẦN 1</span>
              <h3 className="font-bold text-gray-800 text-lg">Trắc nghiệm</h3>
            </div>

            {exam.multipleChoice.map((q, idx) => {
              const isCorrect = isSubmitted && answers[q.id] === q.correctAnswer;
              const isWrong = isSubmitted && answers[q.id] !== q.correctAnswer && answers[q.id];
              const missed = isSubmitted && !answers[q.id];

              return (
                <div 
                  key={q.id} 
                  className={`bg-white rounded-xl shadow-sm border p-4 sm:p-6 transition-all ${
                    isSubmitted 
                      ? isCorrect 
                        ? 'border-green-200 bg-green-50/30' 
                        : isWrong 
                          ? 'border-red-200 bg-red-50/30'
                          : 'border-gray-200'
                      : 'border-gray-200 hover:border-edu-300'
                  }`}
                >
                  <div className="flex gap-3">
                    <span className="flex-shrink-0 w-8 h-8 rounded-full bg-gray-100 text-gray-600 font-bold flex items-center justify-center text-sm">
                      {idx + 1}
                    </span>
                    <div className="flex-1">
                      <p className="font-medium text-gray-800 mb-4 leading-relaxed">{q.question}</p>

                      <div className="space-y-3">
                        {q.options.map((opt, i) => {
                          const key = String.fromCharCode(65 + i); // A, B, C, D
                          const isSelected = answers[q.id] === key;
                          const isThisCorrect = q.correctAnswer === key;

                          let containerClass = "border-gray-200 hover:bg-gray-50 cursor-pointer";
                          let dotClass = "border-gray-300";

                          if (!isSubmitted) {
                            if (isSelected) {
                                containerClass = "border-edu-500 bg-edu-50";
                                dotClass = "border-edu-500 bg-edu-500";
                            }
                          } else {
                            // Submitted state styling
                            if (isThisCorrect) {
                                containerClass = "border-green-500 bg-green-100";
                                dotClass = "border-green-500 bg-green-500";
                            } else if (isSelected && !isThisCorrect) {
                                containerClass = "border-red-500 bg-red-100";
                                dotClass = "border-red-500 bg-red-500";
                            } else {
                                containerClass = "border-gray-200 opacity-60";
                            }
                          }

                          return (
                            <div 
                              key={i}
                              onClick={() => handleOptionSelect(q.id, key)}
                              className={`relative group flex items-start gap-3 p-3 rounded-lg border-2 transition-all ${containerClass}`}
                            >
                              <div className={`w-5 h-5 mt-0.5 rounded-full border-2 flex items-center justify-center flex-shrink-0 transition-colors ${dotClass}`}>
                                {((!isSubmitted && isSelected) || (isSubmitted && (isThisCorrect || isSelected))) && (
                                  <div className="w-2.5 h-2.5 bg-white rounded-full" />
                                )}
                              </div>
                              <span className="text-sm sm:text-base text-gray-800">{cleanOptionText(opt)}</span>

                              {isSubmitted && isThisCorrect && (
                                <CheckCircle className="absolute right-3 top-3 w-5 h-5 text-green-600" />
                              )}
                              {isSubmitted && isSelected && !isThisCorrect && (
                                <XCircle className="absolute right-3 top-3 w-5 h-5 text-red-500" />
                              )}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* Essay Section */}
        {exam.essay.length > 0 && (
          <div className="space-y-6 pt-6">
            <div className="flex items-center gap-2 mb-4 border-b pb-2">
              <span className="bg-edu-600 text-white text-xs font-bold px-2 py-1 rounded">PHẦN 2</span>
              <h3 className="font-bold text-gray-800 text-lg">Tự luận</h3>
            </div>

            {exam.essay.map((q, idx) => (
              <div key={q.id} className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 sm:p-6">
                <div className="flex gap-3 mb-4">
                    <span className="flex-shrink-0 w-8 h-8 rounded-full bg-gray-100 text-gray-600 font-bold flex items-center justify-center text-sm">
                      {idx + 1}
                    </span>
                    <p className="font-medium text-gray-800 leading-relaxed">{q.question}</p>
                </div>

                <textarea 
                  disabled={isSubmitted}
                  placeholder="Nhập câu trả lời của bạn..."
                  className="w-full min-h-[120px] p-3 bg-white border border-gray-300 rounded-lg focus:ring-2 focus:ring-edu-500 outline-none text-gray-900 disabled:bg-gray-100 disabled:text-gray-500"
                ></textarea>

                {isSubmitted && (
                  <div className="mt-4 p-4 bg-yellow-50 border border-yellow-200 rounded-lg animate-fade-in">
                    <h4 className="font-bold text-yellow-800 text-sm mb-1">Gợi ý đáp án / Hướng dẫn chấm:</h4>
                    <p className="text-gray-700 text-sm">{q.rubric}</p>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* Footer Action */}
        {!isSubmitted && (
            <div className="sticky bottom-4 z-30">
                <button 
                onClick={handleSubmit}
                className="w-full bg-edu-600 hover:bg-edu-700 text-white font-bold py-4 rounded-xl shadow-xl flex items-center justify-center gap-2 text-lg transition-transform active:scale-[0.98]"
                >
                <Send className="w-5 h-5" /> Nộp bài
                </button>
            </div>
        )}
      </div>
    </div>
  );
};
